-- ============================================================
-- Additional visit-focused seed data (visits 62-121 + related
-- charts, bills, transactions). Continues IDs/codes above.
-- ============================================================















-- ─────────────────────────────────────────────────────────────────────────────
-- Re-sync identity sequences after seeding.
-- The rows above are inserted with explicit "id" values. Because every table
-- uses `generated BY DEFAULT as identity`, Postgres does NOT advance the
-- sequence when an id is given explicitly. Without this fix, the next app
-- INSERT reuses id=1 and fails with: duplicate key value violates unique
-- constraint "<table>_pkey". This loop bumps every identity sequence to the
-- current MAX(id) so new inserts continue after the seeded data.
DO $$
DECLARE
  r   RECORD;
  seq TEXT;
  maxid BIGINT;
BEGIN
  FOR r IN
    SELECT c.relname AS tbl
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    JOIN pg_attribute a ON a.attrelid = c.oid AND a.attname = 'id'
    WHERE c.relkind = 'r' AND n.nspname = 'public'
      AND a.attidentity IN ('d', 'a')   -- identity columns only
  LOOP
    seq := pg_get_serial_sequence('public.' || quote_ident(r.tbl), 'id');
    IF seq IS NOT NULL THEN
      EXECUTE format('SELECT COALESCE(MAX(id), 0) FROM public.%I', r.tbl) INTO maxid;
      -- is_called = (maxid > 0): when the table is empty, leave the first id at 1
      PERFORM setval(seq, GREATEST(maxid, 1), maxid > 0);
    END IF;
  END LOOP;
END $$;












